import{a0 as t,O as c,P as d,U as r,a6 as s,Q as e,Z as a,X as i,F as o}from"./framework-d6e74f8b.js";const p="/carefree/cursor-pay.png",u="/carefree/cursor-pay-02.png",h="/carefree/cursor-pay-03.png",v="/carefree/cursor-paid.png",m={},b=e("p",null,"作为一个重度vibe coding患者，我得了一种写代码就犯困的病。",-1),k=i('<h2 id="为什么会有这样一个项目" tabindex="-1"><a class="header-anchor" href="#为什么会有这样一个项目" aria-hidden="true">#</a> 为什么会有这样一个项目？</h2><p>正式开始之前，先看看我的cursor支付情况</p><p><img src="'+p+'" alt="" loading="lazy"><img src="'+u+'" alt="" loading="lazy"><img src="'+h+'" alt="" loading="lazy"></p><p>再往前就更多了，于是我在三月份暂停了一部分的支付，转为吹到了天上的claude code cli（三方key，便宜耐造，公司似乎也是这样的，狠狠地薅资本主义羊毛啊！）。</p><p>但是发现，身为一个稍微想关心一下代码质量的开发，我发现太依赖图形能力了，cli要使用多模态，我还需要知道文件路径，先复制到本地，没有浏览器工具，diff只能看片面，无法有效引用上下文甚至行间上下文，写代码像是看黑盒一样，等等问题。</p><p>遂转向codex app（不用claude desktop 是因为a社封号，搞不定），至少是拥有了一定的可视化能力。但是某些问题还是没有改变，比如付费还是很贵，比如还是没有codemap，codeindex等能力，比如基于上下文的提示词补全等。</p><p>遂放弃，改为使用codex/claude code cli + cursor，体感仍一般。那么既然cursor这么好用，有没有一种办法既能使用三方key，又能用cursor丝滑的ai嵌入能力呢？有的兄弟，有的。</p><p>总所周知，cursor支持一切 openai标准接口格式的自定义请求，setting-&gt;model-&gt;apikyes可见，在此处填入你从类openai获取的key，并修改baseUrl，即可使得除auto和claude之外的请求，都走到你的url，使用你自己的额度。</p><p>背景如上，开始实行。</p><h2 id="通信机制" tabindex="-1"><a class="header-anchor" href="#通信机制" aria-hidden="true">#</a> 通信机制</h2><p>先说一下cursor得通信机制：</p>',11),g=e("p",null,"所以，我们的baseUrl收到消息一定是从cursor服务器来的，就需要一个https的域名，而非ip，这是必要条件，否则请求会直接截断。",-1),_=e("p",null,"cursor目前使用的仍然是早期的/v1/chat/complete端口，而非当前的/response端口，所以你自己的服务（或者三方服务）一定要支持接收/v1/chat/complete。",-1),q=e("p",null,"流式请求和响应，这个不用多说了。",-1),f={href:"https://github.com/lljl500220/openai-compat-shim",target:"_blank",rel:"noopener noreferrer"},x=i(`<p>内容核心就是获取到cursor的请求，做拆解，归一化，合并等。代码比较简单，让ai大人看看就知道了。</p><h2 id="设计" tabindex="-1"><a class="header-anchor" href="#设计" aria-hidden="true">#</a> 设计</h2><h3 id="请求流程" tabindex="-1"><a class="header-anchor" href="#请求流程" aria-hidden="true">#</a> 请求流程</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>编辑器 / Cursor / 自定义客户端
        |
        v
openai-compat-shim
  - 鉴权保护
  - 请求解析
  - 请求体适配
  - 可选字段剥离
  - 可选调试抓取
  - 流式透传
        |
        v
OpenAI 兼容上游
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="设计目标" tabindex="-1"><a class="header-anchor" href="#设计目标" aria-hidden="true">#</a> 设计目标</h3><ul><li>尽可能保留原始语义信息</li><li>只规范化那些已知会导致兼容性问题的部分</li><li>除非没有更好的退路，否则不主动把结构化内容压平成纯文本</li><li>保持实现轻量、依赖少，方便部署到小型服务器</li><li>在需要时抓取完整请求/响应记录，降低生产排障成本</li></ul><h3 id="非目标" tabindex="-1"><a class="header-anchor" href="#非目标" aria-hidden="true">#</a> 非目标</h3><ul><li>这不是完整的 OpenAI API 克隆</li><li>这不是会话存储系统</li><li>这个 shim 不会自己执行工具</li><li>它也不会自动修复所有上游兼容性问题</li></ul><h2 id="实现概览" tabindex="-1"><a class="header-anchor" href="#实现概览" aria-hidden="true">#</a> 实现概览</h2><h3 id="_1-鉴权与健康检查接口" tabindex="-1"><a class="header-anchor" href="#_1-鉴权与健康检查接口" aria-hidden="true">#</a> 1. 鉴权与健康检查接口</h3><p>这个 shim 可以用 <code>SHIM_API_KEY</code> 保护 <code>/v1/*</code> 路径。</p><ul><li>客户端发送 <code>Authorization: Bearer &lt;shim-key&gt;</code></li><li>shim 进行校验</li><li>shim 使用 <code>TARGET_API_KEY</code> 转发到上游</li></ul><p>之所以提供 <code>/healthz</code> 和 <code>/v1/models</code>，是为了让客户端在发送真实流量前先探活。</p><h3 id="_2-请求体适配" tabindex="-1"><a class="header-anchor" href="#_2-请求体适配" aria-hidden="true">#</a> 2. 请求体适配</h3><p>核心适配逻辑位于 <code>server.js</code> 里的 <code>adaptPayload()</code>。</p><p>对于 <code>/v1/chat/completions</code>：</p><ul><li>如果客户端本来就发送了原生 <code>messages</code>，则尽量保持不变</li><li>如果客户端发送的是 <code>input</code>，则转换为结构化 <code>messages</code></li><li>保留多轮对话中的角色顺序，而不是把一切折叠成一个字符串</li><li>将工具定义转换为 <code>chat.completions</code> 兼容的 function tools</li></ul><p>对于 <code>/v1/responses</code>：</p><ul><li>保留结构化 <code>input</code></li><li>将字符串 / 对象 / 数组形式的输入标准化为 response items，同时不破坏 tool-call 上下文</li></ul><h3 id="_3-保留-tool-call-上下文" tabindex="-1"><a class="header-anchor" href="#_3-保留-tool-call-上下文" aria-hidden="true">#</a> 3. 保留 tool-call 上下文</h3><p>这个 shim 会保留：</p><ul><li><code>tools</code></li><li><code>tool_choice</code></li><li><code>parallel_tool_calls</code></li><li>assistant 的 <code>tool_calls</code></li><li>tool 结果消息</li><li>类似 <code>function_call_output</code> 这样的结构化 <code>input</code> 项</li></ul><p>这对 agent 风格客户端来说是关键能力。</p><h3 id="_4-流式透传" tabindex="-1"><a class="header-anchor" href="#_4-流式透传" aria-hidden="true">#</a> 4. 流式透传</h3><p>只要满足以下任意一个条件，shim 就会把请求视为流式请求：</p><ul><li><code>body.stream === true</code></li><li><code>body.stream_options != null</code></li><li>请求头中的 <code>Accept</code> 包含 <code>text/event-stream</code></li></ul><p>启用流式后，上游流会被直接透传回客户端。</p><h3 id="_5-调试抓取" tabindex="-1"><a class="header-anchor" href="#_5-调试抓取" aria-hidden="true">#</a> 5. 调试抓取</h3><p>当设置了 <code>DEBUG_CAPTURE_DIR</code> 时，shim 会为每个请求写入一个 JSON 文件，其中包含：</p><ul><li>原始请求体</li><li>发往上游的适配后请求体</li><li>上游状态码和响应头</li><li>上游响应体</li></ul><p>对于这个服务来说，这比抓网络包更有价值，因为 shim 到上游之间是 HTTPS。</p><h2 id="我们遇到的关键-agent-问题" tabindex="-1"><a class="header-anchor" href="#我们遇到的关键-agent-问题" aria-hidden="true">#</a> 我们遇到的关键 agent 问题</h2><h3 id="现象" tabindex="-1"><a class="header-anchor" href="#现象" aria-hidden="true">#</a> 现象</h3><p>Cursor 可以连上服务，但 agent 任务在一轮之后就停住了：</p><ul><li>第一轮模型响应能返回</li><li>后续并没有真正进入多轮工具调用循环</li><li>看起来像是上游“没有 agent 能力”</li></ul><h3 id="一开始怀疑的方向" tabindex="-1"><a class="header-anchor" href="#一开始怀疑的方向" aria-hidden="true">#</a> 一开始怀疑的方向</h3><ul><li>上游 <code>gmncode.cn</code> 可能不支持 tool-calling</li><li>上游可能不支持 <code>responses</code></li><li>上游可能会拒绝强制 <code>tool_choice</code></li></ul><p>这些猜测在某些边缘情况下部分成立，但它们并不是主要阻塞点。</p><h3 id="真正的根因" tabindex="-1"><a class="header-anchor" href="#真正的根因" aria-hidden="true">#</a> 真正的根因</h3><p>shim 里有两个主要兼容性问题。</p><h4 id="根因-1-与工具相关的字段被错误剥离了" tabindex="-1"><a class="header-anchor" href="#根因-1-与工具相关的字段被错误剥离了" aria-hidden="true">#</a> 根因 1：与工具相关的字段被错误剥离了</h4><p>早期版本会删除这些字段：</p><ul><li><code>tools</code></li><li><code>tool_choice</code></li><li><code>parallel_tool_calls</code></li></ul><p>光这一点就足以让 agent 行为失效。</p><h4 id="根因-2-多轮结构化-input-被压平成了单条用户消息" tabindex="-1"><a class="header-anchor" href="#根因-2-多轮结构化-input-被压平成了单条用户消息" aria-hidden="true">#</a> 根因 2：多轮结构化 <code>input</code> 被压平成了单条用户消息</h4><p>这是更深层的问题。</p><p>Cursor 当时把请求发到了 <code>/v1/chat/completions</code>，但请求体使用的是带有多轮结构化对话的 <code>input</code>：</p><ul><li>system 指令</li><li>之前的 user 轮次</li><li>之前的 assistant 轮次</li><li>当前 user 轮次</li><li>工具定义</li></ul><p>旧版 shim 会把整个 <code>input</code> 数组拼成一大段文本，再包装成：</p><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">[</span>
  <span class="token punctuation">{</span>
    <span class="token property">&quot;role&quot;</span><span class="token operator">:</span> <span class="token string">&quot;user&quot;</span><span class="token punctuation">,</span>
    <span class="token property">&quot;content&quot;</span><span class="token operator">:</span> <span class="token string">&quot;huge flattened text...&quot;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这会直接破坏对话结构：</p><ul><li>角色边界丢失</li><li>之前 assistant 轮次不再是 assistant 轮次</li><li>tool call 连续性丢失</li><li>模型看到的已不再是真正的 agent 对话</li></ul><h3 id="第三个兼容性问题" tabindex="-1"><a class="header-anchor" href="#第三个兼容性问题" aria-hidden="true">#</a> 第三个兼容性问题</h3><p>Cursor 的工具定义当时也不是 <code>chat.completions</code> 最偏好的格式。</p><p>真实客户端流量里出现过这样的 tools：</p><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">{</span>
  <span class="token property">&quot;type&quot;</span><span class="token operator">:</span> <span class="token string">&quot;function&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;name&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Shell&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;description&quot;</span><span class="token operator">:</span> <span class="token string">&quot;...&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;parameters&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span> ... <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>甚至还有：</p><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">{</span>
  <span class="token property">&quot;type&quot;</span><span class="token operator">:</span> <span class="token string">&quot;custom&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;name&quot;</span><span class="token operator">:</span> <span class="token string">&quot;ApplyPatch&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;description&quot;</span><span class="token operator">:</span> <span class="token string">&quot;...&quot;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>对于 <code>chat/completions</code>，当工具被转换成下面这种形式时，上游表现会更稳定：</p><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">{</span>
  <span class="token property">&quot;type&quot;</span><span class="token operator">:</span> <span class="token string">&quot;function&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;function&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    <span class="token property">&quot;name&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Shell&quot;</span><span class="token punctuation">,</span>
    <span class="token property">&quot;description&quot;</span><span class="token operator">:</span> <span class="token string">&quot;...&quot;</span><span class="token punctuation">,</span>
    <span class="token property">&quot;parameters&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span> ... <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="我们是怎么修复的" tabindex="-1"><a class="header-anchor" href="#我们是怎么修复的" aria-hidden="true">#</a> 我们是怎么修复的</h2><h3 id="修复-1-默认保留-agent-相关字段" tabindex="-1"><a class="header-anchor" href="#修复-1-默认保留-agent-相关字段" aria-hidden="true">#</a> 修复 1：默认保留 agent 相关字段</h3><p>shim 现在默认不再删除与工具相关的字段。</p><p>取而代之的是，它支持通过下面的环境变量配置需要剥离的顶层字段：</p><ul><li><code>STRIP_FIELDS</code></li></ul><p>默认值：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token assign-left variable">STRIP_FIELDS</span><span class="token operator">=</span>audio
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="修复-2-把-input-转换为真正的多轮-messages" tabindex="-1"><a class="header-anchor" href="#修复-2-把-input-转换为真正的多轮-messages" aria-hidden="true">#</a> 修复 2：把 <code>input</code> 转换为真正的多轮 <code>messages</code></h3><p>对于 <code>/v1/chat/completions</code>，shim 现在会把 <code>input</code> 数组转换为保留角色语义的 chat messages。</p><p>例如：</p><ul><li><code>role: system/user/assistant</code> 的项会保留为各自独立的消息</li><li><code>function_call</code> 项会变成 assistant 的 <code>tool_calls</code></li><li><code>function_call_output</code> 项会变成 <code>role: tool</code> 消息</li><li><code>input_text</code> 和 <code>output_text</code> 内容片段会被标准化为 chat 文本片段</li></ul><p>这正是让 agent 行为恢复正常的关键改动。</p><h3 id="修复-3-把工具定义标准化为-chat-completions-格式" tabindex="-1"><a class="header-anchor" href="#修复-3-把工具定义标准化为-chat-completions-格式" aria-hidden="true">#</a> 修复 3：把工具定义标准化为 chat completions 格式</h3><p>shim 现在会将下面这些工具：</p><ul><li>顶层 <code>function</code> 工具</li><li><code>custom</code> 工具</li></ul><p>转换成 <code>chat.completions</code> 风格的 function tool 定义。</p><p>这样上游就能识别出真正可调用的工具，而不是把它们当成不透明元数据。</p><h3 id="修复-4-增加请求-响应抓取" tabindex="-1"><a class="header-anchor" href="#修复-4-增加请求-响应抓取" aria-hidden="true">#</a> 修复 4：增加请求/响应抓取</h3><p>我们加入了 <code>DEBUG_CAPTURE_DIR</code>，这样就能在生产环境直接查看真实流量，而不是靠猜。</p><p>这让我们可以对比：</p><ul><li>Cursor 实际发送了什么</li><li>shim 实际适配成了什么</li><li>上游实际返回了什么</li></ul><p>整个排查过程也因此从猜测变成了基于证据的分析。</p><h2 id="我们验证过什么" tabindex="-1"><a class="header-anchor" href="#我们验证过什么" aria-hidden="true">#</a> 我们验证过什么</h2><p>我们直接对 <code>https://gmncode.cn/v1</code> 验证了上游行为。</p><p>观测结果如下：</p><ul><li>普通 <code>/v1/chat/completions</code> 可以工作</li><li>带 tools 的 <code>/v1/chat/completions</code> 可以工作</li><li><code>/v1/chat/completions</code> 可以返回 <code>tool_calls</code></li><li><code>/v1/chat/completions</code> 可以接受工具结果后的后续消息</li><li><code>/v1/responses</code> 可以在第一轮返回 function calls</li><li>在我们的测试中，<code>/v1/responses</code> 配合 <code>previous_response_id</code> 的后续调用不够稳定</li><li>某些形态下的强制工具选择，比正常的 <code>tool_choice: &quot;auto&quot;</code> 更不稳定</li></ul><p>因此，对当前这套部署来说，最可靠的路径是：</p><ul><li>让 Cursor 流量继续走 <code>/v1/chat/completions</code></li><li>把混合 <code>input</code> 请求体适配成结构化 <code>messages</code></li><li>把 tools 标准化成 <code>chat.completions</code> 的 function-tool 格式</li></ul><h2 id="配置" tabindex="-1"><a class="header-anchor" href="#配置" aria-hidden="true">#</a> 配置</h2><p>复制示例文件并填入你自己的值：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cp</span> .env.example .env
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>环境变量：</p><ul><li><code>PORT</code>: 监听端口</li><li><code>TARGET_BASE_URL</code>: 上游基础 URL，例如 <code>https://your-provider.example/v1</code></li><li><code>TARGET_API_KEY</code>: 上游服务商的 key</li><li><code>SHIM_API_KEY</code>: 编辑器 / 客户端访问这个 shim 时使用的 key</li><li><code>DEFAULT_MODEL</code>: <code>/v1/models</code> 暴露的默认回退模型名</li><li><code>STRIP_FIELDS</code>: 代理前需要剥离的顶层请求字段，多个值用逗号分隔</li><li><code>DEBUG_CAPTURE_DIR</code>: 保存完整请求/响应抓取文件的目录</li><li><code>NODE_USE_ENV_PROXY</code>: 设为 <code>1</code> 后，Node.js 会让内置 <code>http</code> / <code>https</code> 请求遵循环境变量代理</li><li><code>HTTP_PROXY</code>: 上游出站 HTTP 代理，例如 <code>http://127.0.0.1:7892</code></li><li><code>HTTPS_PROXY</code>: 上游出站 HTTPS 代理，例如 <code>http://127.0.0.1:7892</code></li><li><code>NO_PROXY</code>: 不走代理的地址白名单，例如 <code>127.0.0.1,localhost</code></li></ul><p>示例：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token assign-left variable">PORT</span><span class="token operator">=</span><span class="token number">8787</span>
<span class="token assign-left variable">TARGET_BASE_URL</span><span class="token operator">=</span>https://your-openai-compatible-provider.example/v1
<span class="token assign-left variable">TARGET_API_KEY</span><span class="token operator">=</span>sk-xxxx
<span class="token assign-left variable">SHIM_API_KEY</span><span class="token operator">=</span>replace-with-your-own-secret
<span class="token assign-left variable">DEFAULT_MODEL</span><span class="token operator">=</span>gpt-5.4
<span class="token assign-left variable">STRIP_FIELDS</span><span class="token operator">=</span>audio
<span class="token assign-left variable">DEBUG_CAPTURE_DIR</span><span class="token operator">=</span>
<span class="token assign-left variable">NODE_USE_ENV_PROXY</span><span class="token operator">=</span><span class="token number">1</span>
<span class="token assign-left variable">HTTP_PROXY</span><span class="token operator">=</span>http://127.0.0.1:7892
<span class="token assign-left variable">HTTPS_PROXY</span><span class="token operator">=</span>http://127.0.0.1:7892
<span class="token assign-left variable">NO_PROXY</span><span class="token operator">=</span><span class="token number">127.0</span>.0.1,localhost
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="本地运行" tabindex="-1"><a class="header-anchor" href="#本地运行" aria-hidden="true">#</a> 本地运行</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">export</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">grep</span> <span class="token parameter variable">-v</span> <span class="token string">&#39;^#&#39;</span> .env <span class="token operator">|</span> <span class="token function">xargs</span><span class="token variable">)</span></span>
<span class="token function">npm</span> start
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="使用-pm2-运行" tabindex="-1"><a class="header-anchor" href="#使用-pm2-运行" aria-hidden="true">#</a> 使用 PM2 运行</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">export</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">grep</span> <span class="token parameter variable">-v</span> <span class="token string">&#39;^#&#39;</span> .env <span class="token operator">|</span> <span class="token function">xargs</span><span class="token variable">)</span></span>
pm2 start ecosystem.config.cjs
pm2 save
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>PM2 配置同样会透传这些变量：</p><ul><li><code>STRIP_FIELDS</code></li><li><code>DEBUG_CAPTURE_DIR</code></li><li><code>NODE_USE_ENV_PROXY</code></li><li><code>HTTP_PROXY</code></li><li><code>HTTPS_PROXY</code></li><li><code>NO_PROXY</code></li></ul><h2 id="服务器通过机场代理访问上游" tabindex="-1"><a class="header-anchor" href="#服务器通过机场代理访问上游" aria-hidden="true">#</a> 服务器通过机场代理访问上游</h2><p>如果你的服务器直连 <code>gmncode.cn</code> 很慢，但本机还好，最稳的办法不是改协议层，而是让服务器的出站请求先走本地代理。</p><p>推荐做法：</p><ul><li>服务器运行 <code>mihomo</code> core，而不是运行 <code>Clash Verge Rev</code> 图形客户端</li><li><code>mihomo</code> 使用订阅拉取节点</li><li>本地暴露一个代理端口，例如 <code>127.0.0.1:7892</code></li><li>shim 通过 <code>NODE_USE_ENV_PROXY=1</code> + <code>HTTP_PROXY</code> / <code>HTTPS_PROXY</code> 访问上游</li></ul><p>原因：</p><ul><li><code>Clash Verge Rev</code> 是桌面 GUI 客户端，不适合无头服务器</li><li>当前这个项目使用的是 Node 内置 <code>http</code> / <code>https</code></li><li>从 Node.js <code>v22.21.0</code> 开始，可以通过 <code>NODE_USE_ENV_PROXY=1</code> 让内置网络请求遵循环境变量代理</li></ul><p>相关参考：</p>`,108),y={href:"https://nodejs.org/en/learn/http/enterprise-network-configuration",target:"_blank",rel:"noopener noreferrer"},P={href:"https://wiki.metacubex.one/en/startup/service/",target:"_blank",rel:"noopener noreferrer"},E={href:"https://wiki.metacubex.one/en/config/proxy-providers/",target:"_blank",rel:"noopener noreferrer"},T=i(`<h3 id="_1-准备-mihomo-配置" tabindex="-1"><a class="header-anchor" href="#_1-准备-mihomo-配置" aria-hidden="true">#</a> 1. 准备 Mihomo 配置</h3><p>仓库内提供了一个样板文件：</p><ul><li><a href="./deploy/mihomo/config.yaml.example">deploy/mihomo/config.yaml.example</a></li></ul><p>把其中的订阅地址替换成你自己的订阅链接。</p><h3 id="_2-验证代理是否真的加速" tabindex="-1"><a class="header-anchor" href="#_2-验证代理是否真的加速" aria-hidden="true">#</a> 2. 验证代理是否真的加速</h3><p>在服务器上先验证 <code>mihomo</code> 本地代理本身能正常访问上游：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">curl</span> <span class="token parameter variable">-x</span> http://127.0.0.1:7892 <span class="token parameter variable">-I</span> https://gmncode.cn/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>如果这条请求比直连明显更稳或更快，再让 shim 挂上代理。</p><h3 id="_3-让-shim-走本地代理" tabindex="-1"><a class="header-anchor" href="#_3-让-shim-走本地代理" aria-hidden="true">#</a> 3. 让 shim 走本地代理</h3><p>把 <code>.env</code> 配成类似这样：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token assign-left variable">PORT</span><span class="token operator">=</span><span class="token number">8787</span>
<span class="token assign-left variable">TARGET_BASE_URL</span><span class="token operator">=</span>https://gmncode.cn/v1
<span class="token assign-left variable">TARGET_API_KEY</span><span class="token operator">=</span>sk-xxxx
<span class="token assign-left variable">SHIM_API_KEY</span><span class="token operator">=</span>replace-with-your-own-secret
<span class="token assign-left variable">DEFAULT_MODEL</span><span class="token operator">=</span>gpt-5.4
<span class="token assign-left variable">STRIP_FIELDS</span><span class="token operator">=</span>audio
<span class="token assign-left variable">DEBUG_CAPTURE_DIR</span><span class="token operator">=</span>
<span class="token assign-left variable">NODE_USE_ENV_PROXY</span><span class="token operator">=</span><span class="token number">1</span>
<span class="token assign-left variable">HTTP_PROXY</span><span class="token operator">=</span>http://127.0.0.1:7892
<span class="token assign-left variable">HTTPS_PROXY</span><span class="token operator">=</span>http://127.0.0.1:7892
<span class="token assign-left variable">NO_PROXY</span><span class="token operator">=</span><span class="token number">127.0</span>.0.1,localhost
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_4-systemd-方式部署" tabindex="-1"><a class="header-anchor" href="#_4-systemd-方式部署" aria-hidden="true">#</a> 4. systemd 方式部署</h3><p>仓库内提供了一个 systemd 样板：</p><ul><li><a href="./systemd/openai-compat-shim.service.example">systemd/openai-compat-shim.service.example</a></li></ul><p>要点：</p><ul><li><code>After=mihomo.service</code>，确保代理 core 先起来</li><li><code>EnvironmentFile=/etc/openai-compat-shim.env</code></li><li><code>NODE_USE_ENV_PROXY=1</code></li><li><code>HTTP_PROXY</code> / <code>HTTPS_PROXY</code> 指向本地 <code>mihomo</code> 端口</li></ul><h2 id="请求示例" tabindex="-1"><a class="header-anchor" href="#请求示例" aria-hidden="true">#</a> 请求示例</h2><h3 id="健康检查" tabindex="-1"><a class="header-anchor" href="#健康检查" aria-hidden="true">#</a> 健康检查</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">curl</span> http://127.0.0.1:8787/healthz
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="模型列表" tabindex="-1"><a class="header-anchor" href="#模型列表" aria-hidden="true">#</a> 模型列表</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">curl</span> http://127.0.0.1:8787/v1/models <span class="token punctuation">\\</span>
  <span class="token parameter variable">-H</span> <span class="token string">&quot;Authorization: Bearer replace-with-your-own-secret&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="基础-chat-completion" tabindex="-1"><a class="header-anchor" href="#基础-chat-completion" aria-hidden="true">#</a> 基础 chat completion</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">curl</span> http://127.0.0.1:8787/v1/chat/completions <span class="token punctuation">\\</span>
  <span class="token parameter variable">-H</span> <span class="token string">&quot;Content-Type: application/json&quot;</span> <span class="token punctuation">\\</span>
  <span class="token parameter variable">-H</span> <span class="token string">&quot;Authorization: Bearer replace-with-your-own-secret&quot;</span> <span class="token punctuation">\\</span>
  <span class="token parameter variable">-d</span> <span class="token string">&#39;{
    &quot;model&quot;: &quot;gpt-5.4&quot;,
    &quot;messages&quot;: [
      { &quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;say hello&quot; }
    ]
  }&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="流式-chat-completion" tabindex="-1"><a class="header-anchor" href="#流式-chat-completion" aria-hidden="true">#</a> 流式 chat completion</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">curl</span> <span class="token parameter variable">-N</span> http://127.0.0.1:8787/v1/chat/completions <span class="token punctuation">\\</span>
  <span class="token parameter variable">-H</span> <span class="token string">&quot;Content-Type: application/json&quot;</span> <span class="token punctuation">\\</span>
  <span class="token parameter variable">-H</span> <span class="token string">&quot;Authorization: Bearer replace-with-your-own-secret&quot;</span> <span class="token punctuation">\\</span>
  <span class="token parameter variable">-d</span> <span class="token string">&#39;{
    &quot;model&quot;: &quot;gpt-5.4&quot;,
    &quot;stream&quot;: true,
    &quot;messages&quot;: [
      { &quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;reply with ok only&quot; }
    ]
  }&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="cursor-风格的混合-input-chat-completions" tabindex="-1"><a class="header-anchor" href="#cursor-风格的混合-input-chat-completions" aria-hidden="true">#</a> Cursor 风格的混合 <code>input</code> + chat completions</h3><p>这是最关键的兼容性场景：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">curl</span> http://127.0.0.1:8787/v1/chat/completions <span class="token punctuation">\\</span>
  <span class="token parameter variable">-H</span> <span class="token string">&quot;Content-Type: application/json&quot;</span> <span class="token punctuation">\\</span>
  <span class="token parameter variable">-H</span> <span class="token string">&quot;Authorization: Bearer replace-with-your-own-secret&quot;</span> <span class="token punctuation">\\</span>
  <span class="token parameter variable">-d</span> <span class="token string">&#39;{
    &quot;model&quot;: &quot;gpt-5.4&quot;,
    &quot;input&quot;: [
      { &quot;role&quot;: &quot;system&quot;, &quot;content&quot;: &quot;You are a coding agent.&quot; },
      {
        &quot;role&quot;: &quot;user&quot;,
        &quot;content&quot;: [
          { &quot;type&quot;: &quot;input_text&quot;, &quot;text&quot;: &quot;Use the calc tool to compute 2+2.&quot; }
        ]
      }
    ],
    &quot;tools&quot;: [
      {
        &quot;type&quot;: &quot;function&quot;,
        &quot;name&quot;: &quot;calc&quot;,
        &quot;description&quot;: &quot;Evaluate arithmetic&quot;,
        &quot;parameters&quot;: {
          &quot;type&quot;: &quot;object&quot;,
          &quot;properties&quot;: {
            &quot;expr&quot;: { &quot;type&quot;: &quot;string&quot; }
          },
          &quot;required&quot;: [&quot;expr&quot;]
        }
      }
    ]
  }&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="调试与故障排查" tabindex="-1"><a class="header-anchor" href="#调试与故障排查" aria-hidden="true">#</a> 调试与故障排查</h2><h3 id="_1-开启抓取" tabindex="-1"><a class="header-anchor" href="#_1-开启抓取" aria-hidden="true">#</a> 1. 开启抓取</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token assign-left variable">DEBUG_CAPTURE_DIR</span><span class="token operator">=</span>/path/to/captures
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>重启之后，每个请求都会生成一个 JSON 文件，包含：</p><ul><li><code>originalBody</code></li><li><code>adaptedPayload</code></li><li><code>upstreamStatus</code></li><li><code>upstreamHeaders</code></li><li><code>upstreamBody</code></li></ul><h3 id="_2-先看什么" tabindex="-1"><a class="header-anchor" href="#_2-先看什么" aria-hidden="true">#</a> 2. 先看什么</h3><p>如果 agent 行为异常，优先对比这些点：</p><ul><li>客户端有没有发送 <code>tools</code>？</li><li>客户端发送的是 <code>messages</code> 还是 <code>input</code>？</li><li>经过适配后，shim 是否还保留了多角色结构？</li><li>assistant 输出里有没有 <code>tool_calls</code>？</li><li>上游返回的是 <code>finish_reason: &quot;tool_calls&quot;</code> 还是 <code>finish_reason: &quot;stop&quot;</code>？</li></ul><h3 id="_3-常见失败模式" tabindex="-1"><a class="header-anchor" href="#_3-常见失败模式" aria-hidden="true">#</a> 3. 常见失败模式</h3><h4 id="现象-模型直接回答-没有调用工具" tabindex="-1"><a class="header-anchor" href="#现象-模型直接回答-没有调用工具" aria-hidden="true">#</a> 现象：模型直接回答，没有调用工具</h4><p>检查：</p><ul><li>tools 是否被剥离了？</li><li>tools 是否被标准化成了正确格式？</li><li>多轮 <code>input</code> 是否被压成了一条 user 字符串？</li></ul><h4 id="现象-第一轮能跑-第二轮失败" tabindex="-1"><a class="header-anchor" href="#现象-第一轮能跑-第二轮失败" aria-hidden="true">#</a> 现象：第一轮能跑，第二轮失败</h4><p>检查：</p><ul><li>后续工具结果消息是否被保留为 <code>role: tool</code></li><li><code>function_call_output</code> 是否被正确转换</li><li>上游路径到底是 <code>/chat/completions</code> 还是 <code>/responses</code></li></ul><h4 id="现象-本地正常-生产环境异常" tabindex="-1"><a class="header-anchor" href="#现象-本地正常-生产环境异常" aria-hidden="true">#</a> 现象：本地正常，生产环境异常</h4><p>检查：</p><ul><li>PM2 环境变量是否正确</li><li>重启时是否使用了 <code>--update-env</code></li><li><code>DEBUG_CAPTURE_DIR</code> 是否可写</li><li>Nginx 是否对流式响应做了缓冲或超时截断</li></ul><h3 id="_4-推荐的调试流程" tabindex="-1"><a class="header-anchor" href="#_4-推荐的调试流程" aria-hidden="true">#</a> 4. 推荐的调试流程</h3><ol><li>开启 <code>DEBUG_CAPTURE_DIR</code></li><li>复现一次问题</li><li>打开最新的抓取文件</li><li>对比 <code>originalBody</code> 和 <code>adaptedPayload</code></li><li>确认问题属于哪一类： <ul><li>客户端请求格式</li><li>shim 适配逻辑</li><li>上游兼容性</li><li>服务器出站网络质量</li></ul></li></ol><h3 id="_5-网络层排查顺序" tabindex="-1"><a class="header-anchor" href="#_5-网络层排查顺序" aria-hidden="true">#</a> 5. 网络层排查顺序</h3><p>如果服务器上表现明显比本机差，优先排查网络层，不要先怀疑 agent 协议。</p><p>顺序如下：</p><ol><li>服务器直连 <code>gmncode.cn</code> 测一次</li><li>服务器通过 <code>mihomo</code> 本地代理再测一次</li><li>对比 <code>time_total</code>、握手耗时和首包耗时</li><li>只有在网络层差异不明显时，才继续看 shim 抓包</li></ol><p>示例：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">curl</span> <span class="token parameter variable">-o</span> /dev/null <span class="token parameter variable">-s</span> <span class="token parameter variable">-w</span> <span class="token string">&#39;direct dns=%{time_namelookup} connect=%{time_connect} tls=%{time_appconnect} ttfb=%{time_starttransfer} total=%{time_total}\\n&#39;</span> https://gmncode.cn/v1/models
<span class="token function">curl</span> <span class="token parameter variable">-o</span> /dev/null <span class="token parameter variable">-s</span> <span class="token parameter variable">-x</span> http://127.0.0.1:7892 <span class="token parameter variable">-w</span> <span class="token string">&#39;proxy  dns=%{time_namelookup} connect=%{time_connect} tls=%{time_appconnect} ttfb=%{time_starttransfer} total=%{time_total}\\n&#39;</span> https://gmncode.cn/v1/models
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="部署拓扑" tabindex="-1"><a class="header-anchor" href="#部署拓扑" aria-hidden="true">#</a> 部署拓扑</h2><p>典型生产部署如下：</p><ul><li>公网 HTTPS 域名由 Nginx 提供入口</li><li>Nginx 反向代理到 <code>127.0.0.1:$PORT</code></li><li>编辑器 / 客户端指向 <code>https://your-domain.example/v1</code></li><li>由 PM2 保持 shim 常驻</li></ul><p>参见 <a href="./nginx.example.conf">nginx.example.conf</a>。</p><h2 id="当前已知限制" tabindex="-1"><a class="header-anchor" href="#当前已知限制" aria-hidden="true">#</a> 当前已知限制</h2><ul><li>这个 shim 本身不持久化对话状态</li><li>它依赖客户端主动发送正确的历史轮次</li><li>不同服务商下，<code>responses</code> 配合 <code>previous_response_id</code> 的续接可能仍然不稳定</li><li>一些服务商对 <code>tool_choice</code> 的格式比其他服务商更严格</li></ul><h2 id="维护说明" tabindex="-1"><a class="header-anchor" href="#维护说明" aria-hidden="true">#</a> 维护说明</h2><p>如果新的客户端集成出现问题，不要一开始就靠猜。</p><p>请按顺序用抓取结果回答这几个问题：</p><ol><li>客户端实际发了什么？</li><li>shim 实际转发了什么？</li><li>上游实际返回了什么？</li></ol><p>实际排查中，大多数问题都会落在这几类：</p><ul><li>请求格式不匹配</li><li>工具 schema 不匹配</li><li>多轮上下文被压平</li><li>上游对特定字段更敏感</li></ul><p>这正是 Cursor agent 问题里发生过的事，而真正的修复方式，是保留结构，而不是把结构“简化”掉。</p><h2 id="尚未解决的问题" tabindex="-1"><a class="header-anchor" href="#尚未解决的问题" aria-hidden="true">#</a> 尚未解决的问题</h2><p>目前发现，cursor对于多模态，无法直接使用baseUrl替代，其他所有的tools均可以使用。故只要不主动塞图给他，而是让他基于code的任务，和直接的cursor体验无任何区别。非要用多模态怎么办？反正都是要开pro的，直接换claude模型啊！反正额度不用白不用。</p><p>服务受限于你的三方key，比较看上游脸色，但是用几十块换两千块，我个人还是乐意的。下面是我十天的使用量，至少不用担心钱突然不见了。</p><figure><img src="`+v+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>具体的实施方案，我在仓库readme有详细说明，希望能帮助到你我的朋友～（馕言文语气）</p>',72);function R(O,A){const l=o("Mermaid"),n=o("ExternalLinkIcon");return c(),d("div",null,[b,r(" more "),k,s(l,{id:"mermaid-37",code:"eJxLy8kvT85ILCpRCHHhUlBwjH66p+Hp8u5YBV1dOwWn6KfrFj3r2P589frnu1teLG59sn/hs8b1sUCFTmAFztFP+ye+bGh82rEhubSoOL/o6YQ+LIqdwYpdEIqfz173bEF7YuazOb1PuxY+nbkCpMoFrMo1WunpvulANS/2T3k6e97Tttan63a+39MD5cLcowTS4QrW4Rat9Hz35Gdz5wPFAGb3alk="}),g,_,q,e("p",null,[a("基于以上三点，考虑到目前市面上的三方服务，几乎无法直接接收cursor的请求（封装了tools，message等），我直接写了一个服务用于转换，"),e("a",f,[a("github地"),s(n)]),a("，仅供参考。")]),x,e("ul",null,[e("li",null,[a("Node.js 企业网络配置文档："),e("a",y,[a("https://nodejs.org/en/learn/http/enterprise-network-configuration"),s(n)])]),e("li",null,[a("Mihomo service 文档："),e("a",P,[a("https://wiki.metacubex.one/en/startup/service/"),s(n)])]),e("li",null,[a("Mihomo proxy-providers 文档："),e("a",E,[a("https://wiki.metacubex.one/en/config/proxy-providers/"),s(n)])])]),T])}const I=t(m,[["render",R],["__file","cursor.html.vue"]]);export{I as default};
